SELECT sailor_name
FROM sailors
WHERE sailor_experience = 'Advanced';

SELECT sailor_nationality, COUNT(sailor_id) as number_of_sailors
FROM sailors
GROUP BY sailor_nationality;

SELECT yacht_name, yacht_owner, yacht_length, yacht_weight
FROM yachts
WHERE yacht_length > 20;

SELECT event_name
FROM events
WHERE number_of_races = (SELECT MAX(number_of_races) FROM events);

SELECT yacht_name
FROM yachts
WHERE yacht_id = 0;

SELECT MIN(rank) AS highest_rank
FROM scores
WHERE event_id = 1;
